async fn run_export(
    job_id: &str,
    connection: &ConnectionDto,
    chunks: &[ChunkInput],
    theme: &str,
    format: &str,
    _include_illustrations: bool,
    output_dir: &str,
    cancel: CancellationToken,
) -> Result<String, String> {
    let api_key = get_api_key(&connection.id)
        .map_err(|e| e.to_string())?
