}

async fn process_chunk(
    connection: &ConnectionDto,
    api_key: &str,
    chunk: &ChunkInput,
) -> Result<String, String> {
    let mut messages: Vec<ChatMessage> = vec![ChatMessage {
        role: Role::System,
        content: CHRONICLER_PROMPT.to_string(),
