<body>
<h1>📖 Kronika dobrodružství</h1>
{chapters}
<div class="appendix">
  <p><em>Vygenerováno pomocí MySillyTavern — Kronika export</em></p>
  <p>Téma: {theme} | Formát: {format}</p>
</div>
</body>
</html>"#,
        chapters = prose_sections.join("\n"),
    );

    let ext = if format == "pdf" { "html" } else { "html" };
