use commands::secrets::{delete_api_key, has_api_key, init_store, set_api_key};

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_process::init())
        .plugin(
            tauri_plugin_sql::Builder::default()
                .add_migrations("sqlite:mysillytavern.db", migrations::all_migrations())
                .build(),
        )
        .manage(StreamRegistry::default())
        .manage(ExportRegistry::default())
        .setup(|app| {
            init_store(app.handle())?;
            apply_pending_import(app.handle());
            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            set_api_key,
            delete_api_key,
            has_api_key,
            chat_complete,
            chat_stream,
            chat_abort,
            list_models,
            embed_texts,
            import_card_png,
            export_card_png,
            read_card_json_file,
            ensure_placeholder_avatar,
            read_text_file,
            write_text_file,
            export_backup,
            request_import_backup,
            has_pending_import,
            cancel_pending_import,
            append_log,
            get_log_path,
            eval_dice,
            generate_illustration,
            start_export,
            resume_export,
            get_export_status,
            cancel_export,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

